export const INLINE_JS = "\r\n        (function(){\r\n            var mql = window.matchMedia('(prefers-reduced-motion: reduce)');\r\n            var reduce = mql && mql.matches;\r\n\r\n            // --- Scroll reveal: add .sj-in when [data-reveal] enters viewport ---\r\n            var revealEls = Array.prototype.slice.call(document.querySelectorAll('[data-reveal]'));\r\n            if (reduce || !('IntersectionObserver' in window)) {\r\n                revealEls.forEach(function(el){ el.classList.add('sj-in'); });\r\n            } else {\r\n                var io = new IntersectionObserver(function(entries){\r\n                    entries.forEach(function(entry){\r\n                        if (entry.isIntersecting) {\r\n                            entry.target.classList.add('sj-in');\r\n                            io.unobserve(entry.target);\r\n                        }\r\n                    });\r\n                }, { threshold: 0.14, rootMargin: '0px 0px -8% 0px' });\r\n                revealEls.forEach(function(el){ io.observe(el); });\r\n            }\r\n\r\n            // --- Nav SEOJack lockup: fade in once hero is scrolled past ---\r\n            var lockup = document.querySelector('.nav-seojack-lockup');\r\n            if (lockup) {\r\n                if (reduce) {\r\n                    lockup.classList.add('is-visible');\r\n                } else {\r\n                    var onScroll = function(){\r\n                        if (window.scrollY > 220) { lockup.classList.add('is-visible'); }\r\n                        else { lockup.classList.remove('is-visible'); }\r\n                    };\r\n                    window.addEventListener('scroll', onScroll, { passive: true });\r\n                    onScroll();\r\n                }\r\n            }\r\n\r\n            // --- Live countdown timer ---\r\n            // Target: August 14, 2026 at 12:00 noon UK time (UTC+1 BST)\r\n            var targetDate = new Date('2026-08-14T11:00:00Z');\r\n            var daysEl     = document.querySelector('.countdown-item:nth-child(1) .countdown-value');\r\n            var hoursEl    = document.querySelector('.countdown-item:nth-child(2) .countdown-value');\r\n            var minsEl     = document.querySelector('.countdown-item:nth-child(3) .countdown-value');\r\n            var secsEl     = document.querySelector('.countdown-item:nth-child(4) .countdown-value');\r\n\r\n            function pad(n) { return n < 10 ? '0' + n : '' + n; }\r\n\r\n            function updateCountdown() {\r\n                var now  = Date.now();\r\n                var diff = targetDate.getTime() - now;\r\n                if (diff <= 0) {\r\n                    if (daysEl)  daysEl.textContent  = '00';\r\n                    if (hoursEl) hoursEl.textContent = '00';\r\n                    if (minsEl)  minsEl.textContent  = '00';\r\n                    if (secsEl)  secsEl.textContent  = '00';\r\n                    return;\r\n                }\r\n                var totalSecs = Math.floor(diff / 1000);\r\n                var d = Math.floor(totalSecs / 86400);\r\n                var h = Math.floor((totalSecs % 86400) / 3600);\r\n                var m = Math.floor((totalSecs % 3600) / 60);\r\n                var s = totalSecs % 60;\r\n                if (daysEl)  daysEl.textContent  = '' + d;\r\n                if (hoursEl) hoursEl.textContent = pad(h);\r\n                if (minsEl)  minsEl.textContent  = pad(m);\r\n                if (secsEl)  secsEl.textContent  = pad(s);\r\n            }\r\n\r\n            if (daysEl || hoursEl || minsEl || secsEl) {\r\n                updateCountdown();\r\n                setInterval(updateCountdown, 1000);\r\n            }\r\n\r\n            // --- Schedule tabs ---\r\n            // Schedule data for all three days (all text stays in DOM for SEO via hidden panels)\r\n            var scheduleData = {\r\n                friday: [\r\n                    { time: '3:00 PM',  artist: 'Gates Open',       stage: 'All Stages'   },\r\n                    { time: '4:00 PM',  artist: 'Desert Storm',     stage: 'Sunset Stage' },\r\n                    { time: '6:00 PM',  artist: 'Brass Republic',   stage: 'Main Stage'   },\r\n                    { time: '8:00 PM',  artist: 'The Velvet Waves', stage: 'Main Stage'   },\r\n                    { time: '10:00 PM', artist: 'Aurora Nights',    stage: 'Main Stage'   }\r\n                ],\r\n                saturday: [\r\n                    { time: '12:00 PM', artist: 'Gates Open',     stage: 'All Stages'   },\r\n                    { time: '1:00 PM',  artist: 'Neon Dreams',    stage: 'Sunset Stage' },\r\n                    { time: '3:00 PM',  artist: 'Maya Soul',      stage: 'Main Stage'   },\r\n                    { time: '5:30 PM',  artist: 'DJ Cosmic',      stage: 'Bass Tent'    },\r\n                    { time: '7:30 PM',  artist: 'Brass Republic', stage: 'Main Stage'   },\r\n                    { time: '9:30 PM',  artist: 'Aurora Nights',  stage: 'Main Stage'   }\r\n                ],\r\n                sunday: [\r\n                    { time: '12:00 PM', artist: 'Gates Open',       stage: 'All Stages'   },\r\n                    { time: '2:00 PM',  artist: 'Desert Storm',     stage: 'Sunset Stage' },\r\n                    { time: '4:00 PM',  artist: 'DJ Cosmic',        stage: 'Bass Tent'    },\r\n                    { time: '6:00 PM',  artist: 'Neon Dreams',      stage: 'Main Stage'   },\r\n                    { time: '8:00 PM',  artist: 'Maya Soul',        stage: 'Main Stage'   },\r\n                    { time: '10:00 PM', artist: 'The Velvet Waves', stage: 'Main Stage'   }\r\n                ]\r\n            };\r\n\r\n            var dayKeys = ['friday', 'saturday', 'sunday'];\r\n            var tabs = Array.prototype.slice.call(document.querySelectorAll('.schedule-tab'));\r\n            var scheduleList = document.querySelector('.schedule-list');\r\n\r\n            // Build hidden panels for Saturday and Sunday (Friday is already in DOM)\r\n            // We use three sibling .schedule-panel divs, toggled by display, so all text\r\n            // stays in the DOM for crawlability.\r\n            if (scheduleList && tabs.length === 3) {\r\n                // Wrap existing Friday items into a panel\r\n                var fridayItems = Array.prototype.slice.call(scheduleList.children);\r\n                var fridayPanel = document.createElement('div');\r\n                fridayPanel.className = 'schedule-panel';\r\n                fridayPanel.setAttribute('data-day', 'friday');\r\n                fridayItems.forEach(function(item) { fridayPanel.appendChild(item); });\r\n                scheduleList.appendChild(fridayPanel);\r\n\r\n                // Build Saturday and Sunday panels\r\n                ['saturday', 'sunday'].forEach(function(day) {\r\n                    var panel = document.createElement('div');\r\n                    panel.className = 'schedule-panel';\r\n                    panel.setAttribute('data-day', day);\r\n                    panel.style.display = 'none';\r\n                    scheduleData[day].forEach(function(row) {\r\n                        var item = document.createElement('div');\r\n                        item.className = 'schedule-item';\r\n                        item.innerHTML =\r\n                            '<span class=\"schedule-time\">' + row.time + '</span>' +\r\n                            '<span class=\"schedule-artist\">' + row.artist + '</span>' +\r\n                            '<span class=\"schedule-stage\">' + row.stage + '</span>';\r\n                        panel.appendChild(item);\r\n                    });\r\n                    scheduleList.appendChild(panel);\r\n                });\r\n\r\n                // Wire tab clicks\r\n                tabs.forEach(function(tab, i) {\r\n                    tab.addEventListener('click', function() {\r\n                        tabs.forEach(function(t) { t.classList.remove('active'); });\r\n                        tab.classList.add('active');\r\n                        var panels = Array.prototype.slice.call(scheduleList.querySelectorAll('.schedule-panel'));\r\n                        panels.forEach(function(p, pi) {\r\n                            p.style.display = (pi === i) ? '' : 'none';\r\n                        });\r\n                    });\r\n                });\r\n            }\r\n\r\n            // --- FAQ accordion ---\r\n            // Answers stay in DOM (not removed); we use max-height transition so content is crawlable.\r\n            // Default: all answers open (visible). Clicking toggles collapse.\r\n            var faqItems = Array.prototype.slice.call(document.querySelectorAll('.faq-item'));\r\n            faqItems.forEach(function(item) {\r\n                var question = item.querySelector('.faq-question');\r\n                var answer   = item.querySelector('.faq-answer');\r\n                if (!question || !answer) return;\r\n\r\n                // Set open state by default\r\n                answer.style.overflow   = 'hidden';\r\n                answer.style.transition = reduce ? 'none' : 'max-height 0.35s cubic-bezier(0.22,1,0.36,1), opacity 0.3s ease';\r\n                answer.style.maxHeight  = answer.scrollHeight + 'px';\r\n                answer.style.opacity    = '1';\r\n                question.setAttribute('aria-expanded', 'true');\r\n                question.style.setProperty('--faq-indicator', '\"-\"');\r\n\r\n                question.addEventListener('click', function() {\r\n                    var isOpen = question.getAttribute('aria-expanded') === 'true';\r\n                    if (isOpen) {\r\n                        answer.style.maxHeight = '0';\r\n                        answer.style.opacity   = '0';\r\n                        question.setAttribute('aria-expanded', 'false');\r\n                        question.setAttribute('data-faq-open', 'false');\r\n                    } else {\r\n                        answer.style.maxHeight = answer.scrollHeight + 'px';\r\n                        answer.style.opacity   = '1';\r\n                        question.setAttribute('aria-expanded', 'true');\r\n                        question.setAttribute('data-faq-open', 'true');\r\n                    }\r\n                });\r\n            });\r\n        })();\r\n    ";

